    setError: (error) =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          isLoading: false,
          isError: true,
          errorMessage: error,
        },
      })),

    clearError: () =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          isError: false,
          errorMessage: '',
        },
      })),

    reset: () =>
      set({
        airlineMiles: initialAirlineMilesState,
      }),
  },
});

