     1→import React, { useCallback, useMemo, useRef } from 'react';
     2→import { useFocusEffect, useNavigation, useRoute } from '@react-navigation/native';
     3→import { useWindowDimensions } from 'react-native';
     4→import {
     5→  MARGIN_STANDING_XS,
     6→  PADDING_INNER_LARGER,
     7→} from '@semparar/design-system-app/src/settings/environment';
     8→import { propsItems } from '@semparar/design-system-app/src/atomic/organisms/Accordion/Models';
     9→import { useScreenViewTracking } from '../../hooks/tracking';
    10→import { eventSelectContent, eventScreenViewV3 } from '~/constants/functions';
    11→import { useRootStore } from '../../newArch/store';
    12→import { sanitizeTaxonomy } from '../../utils/functions';
    13→import ApiError from '../../atomic/organisms/ApiError';
    14→import LearnMoreRewardProgramView from './view';
    15→import type { UseLearnMoreRewardProgramReturn } from './Models';
    16→import {
    17→  ParameterPointsProgramStatus,
    18→  ParameterPointsProgramValue,
    19→} from '../../newArch/store/rewardProgram/models';
    20→
    21→export function useLearnMoreRewardProgram(): UseLearnMoreRewardProgramReturn {
    22→  const route = useRoute();
    23→  const navigation = useNavigation();
    24→  const hasFocused = useRef(false);
    25→  const { width } = useWindowDimensions();
    26→  const { status, selectedCategory } = useRootStore((state) => state.parameterPointsProgram);
    27→
    28→  useScreenViewTracking({ route, title: 'Saiba mais' });
    29→
    30→  useFocusEffect(
    31→    useCallback(() => {
    32→      if (!hasFocused.current) {
    33→        eventScreenViewV3('saiba_mais', 'hub_recompensas_spmais', 'monetizacao', {
    34→          location_1: 'monetizacao',
    35→          location_2: 'hub_recompensas_spmais',
    36→          location_3: 'saiba_mais',
    37→        });
    38→        hasFocused.current = true;
    39→      }
    40→      return () => {
    41→        hasFocused.current = false;
    42→      };
    43→    }, [])
    44→  );
    45→
    46→  const widthWithPaddingInnerLarger = Math.ceil(width - PADDING_INNER_LARGER);
    47→  const widthWithPaddingInnerLargerWithMargin = widthWithPaddingInnerLarger - MARGIN_STANDING_XS;
    48→
    49→  const handleNavigation = () => {
    50→    navigation.goBack();
    51→  };
    52→
    53→  const items = useMemo((): propsItems[] => {
    54→    if (
    55→      typeof selectedCategory?.value === 'string' ||
    56→      !selectedCategory?.value?.questions ||
    57→      !selectedCategory?.category
    58→    ) {
    59→      return [];
    60→    }
    61→
    62→    return selectedCategory.value.questions.map(
    63→      (item: { question: string; answer: string }, index: number): propsItems => {
    64→        return {
    65→          id: index,
    66→          title: item.question,
    67→          text: item.answer,
    68→          titleColor: 'BRAND_COMPLEMENT_01',
    69→          headerIconName: (selectedCategory.value as ParameterPointsProgramValue).icon,
    70→          hasSecondaryParagraph: false,
    71→          hideSecondaryIconParagraph: true,
    72→          hideIcon: true,
    73→          onPressCard: () => {
    74→            eventSelectContent({
    75→              content_type: 'cta',
    76→              content_id: sanitizeTaxonomy(item.question),
    77→              location_1: 'monetizacao',
    78→              location_2: 'hub_recompensas_spmais',
    79→              location_3: 'saiba_mais',
    80→            });
    81→          },
    82→        } as propsItems;
    83→      }
    84→    );
    85→  }, [selectedCategory]);
    86→
    87→  const hasError =
    88→    !selectedCategory ||
    89→    typeof selectedCategory?.value === 'string' ||
    90→    status === ParameterPointsProgramStatus.ERROR;
    91→
    92→  return {
    93→    data: items,
    94→    title: selectedCategory?.category || '',
    95→    widthWithPaddingInnerLargerWithMargin,
    96→    onNavigation: handleNavigation,
    97→    hasError,
    98→  };
    99→}
   100→
   101→export default function LearnMoreRewardProgram() {
   102→  const { data, title, widthWithPaddingInnerLargerWithMargin, onNavigation, hasError } =
   103→    useLearnMoreRewardProgram();
   104→
   105→  if (hasError) {
   106→    return <ApiError onPress={onNavigation} />;
   107→  }
   108→
   109→  return (
   110→    <LearnMoreRewardProgramView
   111→      data={data}
   112→      title={title}
   113→      widthWithPaddingInnerLargerWithMargin={widthWithPaddingInnerLargerWithMargin}
   114→      onNavigation={onNavigation}
   115→    />
   116→  );
